		/// <para><see href="https://learn.microsoft.com/windows/win32/api/ddeml/nf-ddeml-ddenameservice#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll"),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
