		[SupportedOSPlatform("windows6.0.6000")]
		[OverloadResolutionPriority(1)]
		public static unsafe int DlgDirList(winmdroot.Foundation.HWND hDlg, ref Span<char>lpPathSpec, int nIDListBox, int nIDStaticPath, winmdroot.UI.Controls.DLG_DIR_LIST_FILE_TYPE uFileType)
		{
			if (lpPathSpec != null && lpPathSpec.LastIndexOf('\0') == -1)				throw new ArgumentException("Required null terminator missing.", "lpPathSpec");
			fixed (char* plpPathSpec = lpPathSpec)
			{
				winmdroot.Foundation.PWSTR wstrlpPathSpec = plpPathSpec;
				int __result = PInvoke.DlgDirList(hDlg, wstrlpPathSpec, nIDListBox, nIDStaticPath, uFileType);
				lpPathSpec = lpPathSpec.Slice(0, wstrlpPathSpec.Length);
				return __result;
			}
		}

		/// <summary>Replaces the contents of a list box with the names of the subdirectories and files in a specified directory. You can filter the list of names by specifying a set of file attributes. The list can optionally include mapped drives. (Unicode)</summary>
		/// <param name="hDlg">
		/// <para>Type: <b><a href="https://docs.microsoft.com/windows/desktop/WinProg/windows-data-types">HWND</a></b> A handle to the dialog box that contains the list box.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirlistw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpPathSpec">
		/// <para>Type: <b><a href="https://docs.microsoft.com/windows/desktop/WinProg/windows-data-types">LPTSTR</a></b> A pointer to a buffer containing a null-terminated string that specifies an absolute path, relative path, or filename. An absolute path can begin with a drive letter (for example, d:\) or a UNC name (for example, \\ <i>machinename</i>\ <i>sharename</i>). The function splits the string into a directory and a filename. The function searches the directory for names that match the filename. If the string does not specify a directory, the function searches the current directory. If the string includes a filename, the filename must contain at least one wildcard character (? or *). If the string does not include a filename, the function behaves as if you had specified the asterisk wildcard character (*) as the filename. All names in the specified directory that match the filename and have the attributes specified by the <i>uFileType</i> parameter are added to the list box.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirlistw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="nIDListBox">
		/// <para>Type: <b>int</b> The identifier of a list box in the <i>hDlg</i> dialog box. If this parameter is zero, <b>DlgDirList</b> does not try to fill a list box.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirlistw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="nIDStaticPath">
		/// <para>Type: <b>int</b> The identifier of a static control in the <i>hDlg</i> dialog box. <b>DlgDirList</b> sets the text of this control to display the current drive and directory. This parameter can be zero if you do not want to display the current drive and directory.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirlistw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="uFileType">Type: <b><a href="https://docs.microsoft.com/windows/desktop/WinProg/windows-data-types">UINT</a></b></param>
		/// <returns>
		/// <para>Type: <b>int</b> If the function succeeds, the return value is nonzero. If the function fails, the return value is zero. For example, if the string specified by <i>lpPathSpec</i> is not a valid path, the function fails. To get extended error information, call .</para>
		/// </returns>
		/// <remarks>
		/// <para>If <i>lpPathSpec</i> specifies a directory, <a href="https://docs.microsoft.com/windows/desktop/api/winuser/nf-winuser-dlgdirlistcomboboxa">DlgDirListComboBox</a> changes the current directory to the specified directory before filling the list box. The text of the static control identified by the <i>nIDStaticPath</i> parameter is set to the name of the new current directory. <b>DlgDirList</b> sends the <a href="https://docs.microsoft.com/windows/desktop/Controls/lb-resetcontent">LB_RESETCONTENT</a> and <a href="https://docs.microsoft.com/windows/desktop/Controls/lb-dir">LB_DIR</a> messages to the list box. If <i>uFileType</i> includes the DDL_DIRECTORY flag and <i>lpPathSpec</i> specifies a first-level directory, such as C:\TEMP, the list box will always include a ".." entry for the root directory. This is true even if the root directory has hidden or system attributes and the DDL_HIDDEN and DDL_SYSTEM flags are not specified. The root directory of an NTFS volume has hidden and system attributes. The directory listing displays long filenames, if any.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirlistw#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll", EntryPoint = "DlgDirListW"),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows6.0.6000")]
		public static partial int DlgDirList(winmdroot.Foundation.HWND hDlg, winmdroot.Foundation.PWSTR lpPathSpec, int nIDListBox, int nIDStaticPath, winmdroot.UI.Controls.DLG_DIR_LIST_FILE_TYPE uFileType);

		/// <inheritdoc cref="DlgDirSelectEx(winmdroot.Foundation.HWND, winmdroot.Foundation.PWSTR, int, int)"/>
		[SupportedOSPlatform("windows6.0.6000")]
		public static unsafe winmdroot.Foundation.BOOL DlgDirSelectEx(winmdroot.Foundation.HWND hwndDlg, Span<char>lpString, int idListBox)
		{
			fixed (char* lpStringLocal = lpString)
			{
				winmdroot.Foundation.BOOL __result = PInvoke.DlgDirSelectEx(hwndDlg, lpStringLocal, lpString.Length, idListBox);
				return __result;
			}
		}

		/// <summary>Retrieves the current selection from a single-selection list box. It assumes that the list box has been filled by the DlgDirList function and that the selection is a drive letter, filename, or directory name. (Unicode)</summary>
		/// <param name="hwndDlg">
		/// <para>Type: <b><a href="https://docs.microsoft.com/windows/desktop/WinProg/windows-data-types">HWND</a></b> A handle to the dialog box that contains the list box.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirselectexw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpString">
		/// <para>Type: <b><a href="https://docs.microsoft.com/windows/desktop/WinProg/windows-data-types">LPTSTR</a></b> A pointer to a buffer that receives the selected path.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirselectexw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="chCount">
		/// <para>Type: <b>int</b> The length, in <b>TCHARs</b>, of the buffer pointed to by <i>lpString</i>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirselectexw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="idListBox">
		/// <para>Type: <b>int</b> The identifier of a list box in the dialog box.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirselectexw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>Type: <b><a href="https://docs.microsoft.com/windows/desktop/WinProg/windows-data-types">BOOL</a></b> If the current selection is a directory name, the return value is nonzero. If the current selection is not a directory name, the return value is zero. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>The <b>DlgDirSelectEx</b> function copies the selection to the buffer pointed to by the <i>lpString</i> parameter. If the current selection is a directory name or drive letter, <b>DlgDirSelectEx</b> removes the enclosing square brackets (and hyphens, for drive letters), so that the name or letter is ready to be inserted into a new path. If there is no selection, <i>lpString</i> does not change. If the string is as long or longer than the buffer, the buffer will contain the truncated string with a terminating null character. <b>DlgDirSelectEx</b> sends <a href="https://docs.microsoft.com/windows/desktop/Controls/lb-getcursel">LB_GETCURSEL</a> and <a href="https://docs.microsoft.com/windows/desktop/Controls/lb-gettext">LB_GETTEXT</a> messages to the list box. The function does not allow more than one filename to be returned from a list box. The list box must not be a multiple-selection list box. If it is, this function does not return a zero value and <i>lpString</i> remains unchanged. <b>Windows 95 or later</b>: <b>DlgDirSelectExW</b> is supported by the Microsoft Layer for Unicode. To use this, you must add certain files to your application, as outlined in <a href="https://docs.microsoft.com/archive/msdn-magazine/2001/october/mslu-develop-unicode-applications-for-windows-9x-platforms-with-the-microsoft-layer-for-unicode">Microsoft Layer for Unicode on Windows Me/98/95 Systems</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirselectexw#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll", EntryPoint = "DlgDirSelectExW", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows6.0.6000")]
		public static partial winmdroot.Foundation.BOOL DlgDirSelectEx(winmdroot.Foundation.HWND hwndDlg, winmdroot.Foundation.PWSTR lpString, int chCount, int idListBox);

		/// <inheritdoc cref="DlgDirListComboBox(winmdroot.Foundation.HWND, winmdroot.Foundation.PWSTR, int, int, winmdroot.UI.Controls.DLG_DIR_LIST_FILE_TYPE)"/>
		[SupportedOSPlatform("windows6.0.6000")]
		[OverloadResolutionPriority(1)]
		public static unsafe int DlgDirListComboBox(winmdroot.Foundation.HWND hDlg, ref Span<char>lpPathSpec, int nIDComboBox, int nIDStaticPath, winmdroot.UI.Controls.DLG_DIR_LIST_FILE_TYPE uFiletype)
		{
			if (lpPathSpec != null && lpPathSpec.LastIndexOf('\0') == -1)				throw new ArgumentException("Required null terminator missing.", "lpPathSpec");
			fixed (char* plpPathSpec = lpPathSpec)
			{
				winmdroot.Foundation.PWSTR wstrlpPathSpec = plpPathSpec;
				int __result = PInvoke.DlgDirListComboBox(hDlg, wstrlpPathSpec, nIDComboBox, nIDStaticPath, uFiletype);
				lpPathSpec = lpPathSpec.Slice(0, wstrlpPathSpec.Length);
				return __result;
			}
		}

		/// <summary>Replaces the contents of a combo box with the names of the subdirectories and files in a specified directory. You can filter the list of names by specifying a set of file attributes. The list of names can include mapped drive letters. (Unicode)</summary>
		/// <param name="hDlg">
		/// <para>Type: <b><a href="https://docs.microsoft.com/windows/desktop/WinProg/windows-data-types">HWND</a></b> A handle to the dialog box that contains the combo box.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirlistcomboboxw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpPathSpec">
		/// <para>Type: <b><a href="https://docs.microsoft.com/windows/desktop/WinProg/windows-data-types">LPTSTR</a></b> A pointer to a buffer containing a null-terminated string that specifies an absolute path, relative path, or file name. An absolute path can begin with a drive letter (for example, d:\) or a UNC name (for example, &#92;&#92;<i>machinename</i>&#92;<i>sharename</i>).</para>
		/// <para>The function splits the string into a directory and a file name. The function searches the directory for names that match the file name. If the string does not specify a directory, the function searches the current directory. If the string includes a file name, the file name must contain at least one wildcard character (? or *). If the string does not include a file name, the function behaves as if you had specified the asterisk wildcard character (*) as the file name. All names in the specified directory that match the file name and have the attributes specified by the <i>uFiletype</i> parameter are added to the list displayed in the combo box.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirlistcomboboxw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="nIDComboBox">
		/// <para>Type: <b>int</b> The identifier of a combo box in the <i>hDlg</i> dialog box. If this parameter is zero, <b>DlgDirListComboBox</b> does not try to fill a combo box.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirlistcomboboxw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="nIDStaticPath">
		/// <para>Type: <b>int</b> The identifier of a static control in the <i>hDlg</i> dialog box. <b>DlgDirListComboBox</b> sets the text of this control to display the current drive and directory. This parameter can be zero if you do not want to display the current drive and directory.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirlistcomboboxw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="uFiletype">Type: <b><a href="https://docs.microsoft.com/windows/desktop/WinProg/windows-data-types">UINT</a></b></param>
		/// <returns>
		/// <para>Type: <b>int</b> If the function succeeds, the return value is nonzero.</para>
		/// <para>If the function fails, the return value is zero. For example, if the string specified by <i>lpPathSpec</i> is not a valid path, the function fails. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>If <i>lpPathSpec</i> specifies a directory, <b>DlgDirListComboBox</b> changes the current directory to the specified directory before filling the combo box. The text of the static control identified by the <i>nIDStaticPath</i> parameter is set to the name of the new current directory.</para>
		/// <para><b>DlgDirListComboBox</b> sends the <a href="https://docs.microsoft.com/windows/desktop/Controls/cb-resetcontent">CB_RESETCONTENT</a> and <a href="https://docs.microsoft.com/windows/desktop/Controls/cb-dir">CB_DIR</a> messages to the combo box. Microsoft Windows NT 4.0 and later: If <i>uFiletype</i> includes the DDL_DIRECTORY flag and <i>lpPathSpec</i> specifies a first-level directory, such as C:\TEMP, the combo box will always include a ".." entry for the root directory. This is true even if the root directory has hidden or system attributes and the DDL_HIDDEN and DDL_SYSTEM flags are not specified. The root directory of an NTFS volume has hidden and system attributes. <b>Security Warning:  </b>Using this function incorrectly might compromise the security of your program. Incorrect use of this function includes having <i>lpPathSpec</i> indicate a non-writable buffer, or a buffer without a null-termination. You should review the <a href="https://docs.microsoft.com/windows/desktop/Controls/sec-comctls">Security Considerations: Microsoft Windows Controls</a> before continuing. Microsoft Windows NT 4.0 and later: The list displays long file names, if any. Windows 95 or later: The list displays short file names (the 8.3 form). You can use the <a href="https://docs.microsoft.com/windows/desktop/api/shellapi/nf-shellapi-shgetfileinfoa">SHGetFileInfo</a> or <a href="https://docs.microsoft.com/windows/desktop/api/fileapi/nf-fileapi-getfullpathnamea">GetFullPathName</a> functions to get the corresponding long file name.</para>
		/// <para>Windows 95 or later: <b>DlgDirListComboBoxW</b> is supported by the Microsoft Layer for Unicode. To use this, you must add certain files to your application, as outlined in <a href="https://docs.microsoft.com/archive/msdn-magazine/2001/october/mslu-develop-unicode-applications-for-windows-9x-platforms-with-the-microsoft-layer-for-unicode">Microsoft Layer for Unicode on Windows Me/98/95 Systems</a>.</para>
		/// <para>> [!NOTE] > The winuser.h header defines DlgDirListComboBox as an alias which automatically selects the ANSI or Unicode version of this function based on the definition of the UNICODE preprocessor constant. Mixing usage of the encoding-neutral alias with code that not encoding-neutral can lead to mismatches that result in compilation or runtime errors. For more information, see [Conventions for Function Prototypes](/windows/win32/intl/conventions-for-function-prototypes).</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-dlgdirlistcomboboxw#">Read more on learn.microsoft.com</see>.</para>
