		/// <summary>Overrides the default per-monitor DPI scaling behavior of a child window in a dialog.</summary>
		/// <param name="hWnd">A handle for the window whose behavior will be modified.</param>
		/// <param name="mask">A mask specifying the subset of flags to be changed.</param>
		/// <param name="values">The desired value to be set for the specified subset of flags.</param>
		/// <returns>
		/// <para>This function returns TRUE if the operation was successful, and FALSE otherwise. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>. Possible errors are <b>ERROR_INVALID_HANDLE</b> if passed an invalid HWND, and <b>ERROR_ACCESS_DENIED</b> if the windows belongs to another process.</para>
		/// </returns>
		/// <remarks>
		/// <para>The behaviors are specified as values from the <a href="https://docs.microsoft.com/windows/desktop/api/winuser/ne-winuser-dialog_control_dpi_change_behaviors">DIALOG_CONTROL_DPI_CHANGE_BEHAVIORS</a> enum. This function follows the typical two-parameter approach to setting flags, where a mask specifies the subset of the flags to be changed. It is valid to set these behaviors on <i>any</i> window. It does not matter if the window is currently a child of a dialog at the point in time that SetDialogControlDpiChangeBehavior is called. The behaviors are retained and will take effect only when the window is an immediate child of a dialog that has per-monitor DPI scaling enabled. This API influences individual controls within dialogs. The dialog-wide per-monitor DPI scaling behavior is controlled by <a href="https://docs.microsoft.com/windows/desktop/api/winuser/nf-winuser-setdialogdpichangebehavior">SetDialogDpiChangeBehavior</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-setdialogcontroldpichangebehavior#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows10.0.15063")]
		public static partial winmdroot.Foundation.BOOL SetDialogControlDpiChangeBehavior(winmdroot.Foundation.HWND hWnd, winmdroot.UI.HiDpi.DIALOG_CONTROL_DPI_CHANGE_BEHAVIORS mask, winmdroot.UI.HiDpi.DIALOG_CONTROL_DPI_CHANGE_BEHAVIORS values);

		/// <summary>Retrieves and per-monitor DPI scaling behavior overrides of a child window in a dialog.</summary>
		/// <param name="hWnd">The handle for the window to examine.</param>
		/// <returns>The flags set on the given window. If passed an invalid handle, this function will return zero, and set its <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">last error</a> to <b>ERROR_INVALID_HANDLE</b>.</returns>
		/// <remarks>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-getdialogcontroldpichangebehavior">Learn more about this API from learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows10.0.15063")]
		public static partial winmdroot.UI.HiDpi.DIALOG_CONTROL_DPI_CHANGE_BEHAVIORS GetDialogControlDpiChangeBehavior(winmdroot.Foundation.HWND hWnd);

		/// <summary>Dialogs in Per-Monitor v2 contexts are automatically DPI scaled. This method lets you customize their DPI change behavior.</summary>
		/// <param name="hDlg">A handle for the dialog whose behavior will be modified.</param>
		/// <param name="mask">A mask specifying the subset of flags to be changed.</param>
		/// <param name="values">The desired value to be set for the specified subset of flags.</param>
		/// <returns>
		/// <para>This function returns TRUE if the operation was successful, and FALSE otherwise. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>. Possible errors are <b>ERROR_INVALID_HANDLE</b> if passed an invalid dialog HWND, and <b>ERROR_ACCESS_DENIED</b> if the dialog belongs to another process.</para>
		/// </returns>
		/// <remarks>
		/// <para>For extensibility, <a href="https://docs.microsoft.com/windows/desktop/api/winuser/ne-winuser-dialog_dpi_change_behaviors">DIALOG_DPI_CHANGE_BEHAVIORS</a> was modeled as a set of bit-flags representing separate behaviors. This function follows the typical two-parameter approach to setting flags, where a mask specifies the subset of the flags to be changed. It is not an error to call this API outside of Per Monitor v2 contexts, though the flags will have no effect on the behavior of the specified dialog until the context is changed to Per Monitor v2.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-setdialogdpichangebehavior#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
