		public static partial winmdroot.Foundation.BOOL SetDialogDpiChangeBehavior(winmdroot.Foundation.HWND hDlg, winmdroot.UI.HiDpi.DIALOG_DPI_CHANGE_BEHAVIORS mask, winmdroot.UI.HiDpi.DIALOG_DPI_CHANGE_BEHAVIORS values);

		/// <summary>Returns the flags that might have been set on a given dialog by an earlier call to SetDialogDpiChangeBehavior.</summary>
		/// <param name="hDlg">The handle for the dialog to examine.</param>
		/// <returns>The flags set on the given dialog. If passed an invalid handle, this function will return zero, and set its <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">last error</a> to <b>ERROR_INVALID_HANDLE</b>.</returns>
		/// <remarks>It can be difficult to distinguish between a return value of <b>DDC_DEFAULT</b> and the error case, which is zero. To determine between the two, it is recommended that you call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError()</a> to check the error.</remarks>
		[LibraryImport("USER32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
