		/// <summary>Loads a new input locale identifier (formerly called the keyboard layout) into the system. (Unicode)</summary>
		/// <param name="pwszKLID">
		/// <para>Type: <b>LPCTSTR</b> The name of the input locale identifier to load. This name is a string composed of the hexadecimal value of the <a href="https://docs.microsoft.com/windows/desktop/Intl/language-identifiers">Language Identifier</a> (low word) and a device identifier (high word). For example, U.S. English has a language identifier of 0x0409, so the primary U.S. English layout is named "00000409". Variants of U.S. English layout (such as the Dvorak layout) are named "00010409", "00020409", and so on. For a list of the input layouts that are supplied with Windows, see [Keyboard Identifiers and Input Method Editors for Windows](/windows-hardware/manufacture/desktop/windows-language-pack-default-values).</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-loadkeyboardlayoutw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="Flags">Type: <b>UINT</b></param>
		/// <returns>
		/// <para>Type: <b>HKL</b> If the function succeeds, the return value is the input locale identifier corresponding to the name specified in <i>pwszKLID</i>. If no matching locale is available, the return value is the default language of the system. If the function fails, the return value is NULL. This can occur if the layout library is loaded from the application directory. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>The input locale identifier is a broader concept than a keyboard layout, since it can also encompass a speech-to-text converter, an Input Method Editor (IME), or any other form of input. An application can and will typically load the default input locale identifier or IME for a language and can do so by specifying only a string version of the language identifier. If an application wants to load a specific locale or IME, it should read the registry to determine the specific input locale identifier to pass to <b>LoadKeyboardLayout</b>. In this case, a request to activate the default input locale identifier for a locale will activate the first matching one. A specific IME should be activated using an explicit input locale identifier returned from <a href="https://docs.microsoft.com/windows/desktop/api/winuser/nf-winuser-getkeyboardlayout">GetKeyboardLayout</a> or <b>LoadKeyboardLayout</b>. <b>Prior to Windows 8:</b> This function only affects the layout for the current process or thread. <b>Beginning in  Windows 8:</b> This function affects the layout for the entire system. > [!NOTE] > The winuser.h header defines LoadKeyboardLayout as an alias which automatically selects the ANSI or Unicode version of this function based on the definition of the UNICODE preprocessor constant. Mixing usage of the encoding-neutral alias with code that not encoding-neutral can lead to mismatches that result in compilation or runtime errors. For more information, see [Conventions for Function Prototypes](/windows/win32/intl/conventions-for-function-prototypes).</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-loadkeyboardlayoutw#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll", EntryPoint = "LoadKeyboardLayoutW", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.0")]
		public static partial winmdroot.UI.Input.KeyboardAndMouse.HKL LoadKeyboardLayout(winmdroot.Foundation.PCWSTR pwszKLID, winmdroot.UI.Input.KeyboardAndMouse.ACTIVATE_KEYBOARD_LAYOUT_FLAGS Flags);

		/// <inheritdoc cref="ActivateKeyboardLayout(winmdroot.UI.Input.KeyboardAndMouse.HKL, winmdroot.UI.Input.KeyboardAndMouse.ACTIVATE_KEYBOARD_LAYOUT_FLAGS)"/>
		[SupportedOSPlatform("windows5.0")]
		[OverloadResolutionPriority(1)]
		public static unsafe global::Windows.Win32.UnloadKeyboardLayoutSafeHandle ActivateKeyboardLayout(SafeHandle hkl, winmdroot.UI.Input.KeyboardAndMouse.ACTIVATE_KEYBOARD_LAYOUT_FLAGS Flags)
		{
			bool hklAddRef = false;
			try
			{
				winmdroot.UI.Input.KeyboardAndMouse.HKL hklLocal;
				if (hkl is object)
				{
					hkl.DangerousAddRef(ref hklAddRef);
					hklLocal = (winmdroot.UI.Input.KeyboardAndMouse.HKL)hkl.DangerousGetHandle();
				}
				else
					throw new ArgumentNullException(nameof(hkl));
				global::Windows.Win32.UnloadKeyboardLayoutSafeHandle __resultSafeHandle = new global::Windows.Win32.UnloadKeyboardLayoutSafeHandle(default, ownsHandle: true);
				winmdroot.UI.Input.KeyboardAndMouse.HKL __result = PInvoke.ActivateKeyboardLayout(hklLocal, Flags);
				global::System.Runtime.InteropServices.Marshal.InitHandle(__resultSafeHandle, __result);
				return __resultSafeHandle;
			}
			finally
			{
				if (hklAddRef)
					hkl.DangerousRelease();
			}
		}

		/// <summary>Sets the input locale identifier (formerly called the keyboard layout handle) for the calling thread or the current process. The input locale identifier specifies a locale as well as the physical layout of the keyboard.</summary>
		/// <param name="hkl">
		/// <para>Type: <b>HKL</b> Input locale identifier to be activated.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-activatekeyboardlayout#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="Flags">Type: <b>UINT</b></param>
		/// <returns>
		/// <para>Type: <b>HKL</b> The return value is of type <b>HKL</b>. If the function succeeds, the return value is the previous input locale identifier. Otherwise, it is zero. To get extended error information, use the <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a> function.</para>
		/// </returns>
		/// <remarks>
		/// <para>This function only affects the layout for the current process or thread. This function is not restricted to keyboard layouts. The <i>hkl</i> parameter is actually an input locale identifier. This is a broader concept than a keyboard layout, since it can also encompass a speech-to-text converter, an Input Method Editor (IME), or any other form of input. Several input locale identifiers can be loaded at any one time, but only one is active at a time. Loading multiple input locale identifiers makes it possible to rapidly switch between them. When multiple IMEs are allowed for each locale, passing an input locale identifier in which the high word (the device handle) is zero activates the first IME in the list belonging to the locale. The <b>KLF_RESET</b> and <b>KLF_SHIFTLOCK</b> flags alter the method by which the Caps Lock state is turned off. By default, the Caps Lock state is turned off by hitting the Caps Lock key again. If only <b>KLF_RESET</b> is set, the default state is reestablished. If <b>KLF_RESET</b> and <b>KLF_SHIFTLOCK</b> are set, the Caps Lock state is turned off by pressing either Caps Lock key. This feature is used to conform to local keyboard behavior standards as well as for personal preferences.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-activatekeyboardlayout#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.0")]
		public static partial winmdroot.UI.Input.KeyboardAndMouse.HKL ActivateKeyboardLayout(winmdroot.UI.Input.KeyboardAndMouse.HKL hkl, winmdroot.UI.Input.KeyboardAndMouse.ACTIVATE_KEYBOARD_LAYOUT_FLAGS Flags);

		/// <inheritdoc cref="ToUnicodeEx(uint, uint, byte*, winmdroot.Foundation.PWSTR, int, uint, winmdroot.UI.Input.KeyboardAndMouse.HKL)"/>
		[SupportedOSPlatform("windows5.0")]
		public static unsafe int ToUnicodeEx(uint wVirtKey, uint wScanCode, ReadOnlySpan<byte> lpKeyState, Span<char>pwszBuff, uint wFlags, [Optional] SafeHandle dwhkl)
		{
			bool dwhklAddRef = false;
			try
			{
				fixed (char* pwszBuffLocal = pwszBuff)
				{
					fixed (byte* lpKeyStateLocal = lpKeyState)
					{
						if (lpKeyState.Length < 256)							throw new ArgumentException();
						winmdroot.UI.Input.KeyboardAndMouse.HKL dwhklLocal;
						if (dwhkl is object)
						{
							dwhkl.DangerousAddRef(ref dwhklAddRef);
							dwhklLocal = (winmdroot.UI.Input.KeyboardAndMouse.HKL)dwhkl.DangerousGetHandle();
						}
						else
							dwhklLocal = (winmdroot.UI.Input.KeyboardAndMouse.HKL )new IntPtr(0L);
						int __result = PInvoke.ToUnicodeEx(wVirtKey, wScanCode, lpKeyStateLocal, pwszBuffLocal, pwszBuff.Length, wFlags, dwhklLocal);
						return __result;
					}
				}
			}
			finally
			{
				if (dwhklAddRef)
					dwhkl.DangerousRelease();
			}
		}

		/// <summary>Translates the specified virtual-key code and keyboard state to the corresponding Unicode character or characters. (ToUnicodeEx)</summary>
		/// <param name="wVirtKey">
		/// <para>Type: <b>UINT</b> The virtual-key code to be translated. See <a href="https://docs.microsoft.com/windows/desktop/inputdev/virtual-key-codes">Virtual-Key Codes</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-tounicodeex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="wScanCode">
		/// <para>Type: <b>UINT</b> The hardware <a href="https://docs.microsoft.com/windows/win32/inputdev/about-keyboard-input#scan-codes">scan code</a> of the key to be translated. The high-order bit of this value is set if the key is up.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-tounicodeex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpKeyState">
		/// <para>Type: <b>const BYTE*</b> A pointer to a 256-byte array that contains the current keyboard state. Each element (byte) in the array contains the state of one key. If the high-order bit of a byte is set, the key is down. The low bit, if set, indicates that the key is toggled on. In this function, only the toggle bit of the CAPS LOCK key is relevant. The toggle state of the NUM LOCK and SCROLL LOCK keys is ignored. See <a href="https://docs.microsoft.com/windows/win32/api/winuser/nf-winuser-getkeyboardstate">GetKeyboardState</a> for more info.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-tounicodeex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="pwszBuff">
		/// <para>Type: <b>LPWSTR</b> The buffer that receives the translated character or characters as array of UTF-16 code units. This buffer may be returned without being null-terminated even though the variable name suggests that it is null-terminated. You can use the return value of this method to determine how many characters were written.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-tounicodeex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="cchBuff">
		/// <para>Type: <b>int</b> The size, in characters, of the buffer pointed to by the <i>pwszBuff</i> parameter.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-tounicodeex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="wFlags">
		/// <para>Type: <b>UINT</b> The behavior of the function. If bit 0 is set, a menu is active. In this mode <b>Alt+Numeric keypad</b> key combinations are not handled. If bit 1 is set, **ToUnicodeEx** will translate scancodes marked as key break events in addition to its usual treatment of key make events. If bit 2 is set, keyboard state is not changed (Windows 10, version 1607 and newer) All other bits (through 31) are reserved.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-tounicodeex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwhkl">
		/// <para>Type: <b>HKL</b> The input locale identifier used to translate the specified code. This parameter can be any input locale identifier previously returned by the <a href="https://docs.microsoft.com/windows/desktop/api/winuser/nf-winuser-loadkeyboardlayouta">LoadKeyboardLayout</a> function.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-tounicodeex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>Type: <b>int</b> The function returns one of the following values. </para>
		/// <para>This doc was truncated.</para>
		/// </returns>
		/// <remarks>
		/// <para>The input locale identifier is a broader concept than a keyboard layout, since it can also encompass a speech-to-text converter, an Input Method Editor (IME), or any other form of input. Some keyboard layouts may return several characters and/or supplementary characters as <a href="https://docs.microsoft.com/windows/win32/intl/surrogates-and-supplementary-characters">surrogate pairs</a> in <i>pwszBuff</i>. If dead key character (accent or diacritic) stored in the keyboard layout could not be combined with the specified virtual key to form a single character then the previous entered dead character can be combined with the current character. The parameters supplied to the <b>ToUnicodeEx</b> function might not be sufficient to translate the virtual-key code because a previous <a href="https://docs.microsoft.com/windows/win32/inputdev/about-keyboard-input#dead-character-messages">dead key</a> is stored in the keyboard layout. Typically, <b>ToUnicodeEx</b> performs the translation based on the virtual-key code. In some cases, however, bit 15 of the <i>wScanCode</i> parameter can be used to distinguish between a key press and a key release (for example for ALT+numpad key entry). As <b>ToUnicodeEx</b> translates the virtual-key code, it also changes the state of the kernel-mode keyboard buffer. This state-change affects dead keys, ligatures, <b>Alt+Numeric keypad</b> key entry, and so on. It might also cause undesired side-effects if used in conjunction with <a href="https://docs.microsoft.com/windows/desktop/api/winuser/nf-winuser-translatemessage">TranslateMessage</a> (which also changes the state of the kernel-mode keyboard buffer).</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-tounicodeex#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll"),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.0")]
		public static unsafe partial int ToUnicodeEx(uint wVirtKey, uint wScanCode, byte* lpKeyState, winmdroot.Foundation.PWSTR pwszBuff, int cchBuff, uint wFlags, [Optional] winmdroot.UI.Input.KeyboardAndMouse.HKL dwhkl);

