		/// <param name="uVirtKey">
		/// <para>Type: <b>UINT</b> The virtual-key code to be translated. See <a href="https://docs.microsoft.com/windows/desktop/inputdev/virtual-key-codes">Virtual-Key Codes</a>.</para>
