		/// </param>
		/// <returns>
		/// <para>Type: <b>int</b> The return value is one of the following values. </para>
		/// <para>This doc was truncated.</para>
		/// </returns>
		/// <remarks>
		/// <para>The parameters supplied to the <b>ToAscii</b> function might not be sufficient to translate the virtual-key code, because a previous dead key is stored in the keyboard layout. Typically, <b>ToAscii</b> performs the translation based on the virtual-key code. In some cases, however, bit 15 of the <i>uScanCode</i> parameter may be used to distinguish between a key press and a key release. The scan code is used for translating ALT+ <i>number key</i> combinations. Although NUM LOCK is a toggle key that affects keyboard behavior, <b>ToAscii</b> ignores the toggle setting (the low bit) of <i>lpKeyState</i> (<b>VK_NUMLOCK</b>) because the <i>uVirtKey</i> parameter alone is sufficient to distinguish the cursor movement keys (<b>VK_HOME</b>, <b>VK_INSERT</b>, and so on) from the numeric keys (<b>VK_DECIMAL</b>, <b>VK_NUMPAD0</b> - <b>VK_NUMPAD9</b>).</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-toascii#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll"),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.0")]
		public static unsafe partial int ToAscii(uint uVirtKey, uint uScanCode, [Optional] byte* lpKeyState, ushort* lpChar, uint uFlags);

		/// <inheritdoc cref="ToAsciiEx(uint, uint, byte*, ushort*, uint, winmdroot.UI.Input.KeyboardAndMouse.HKL)"/>
		[SupportedOSPlatform("windows5.0")]
		[OverloadResolutionPriority(1)]
		public static unsafe int ToAsciiEx(uint uVirtKey, uint uScanCode, [Optional] ReadOnlySpan<byte> lpKeyState, out ushort lpChar, uint uFlags, [Optional] SafeHandle dwhkl)
		{
			bool dwhklAddRef = false;
			try
			{
				fixed (ushort* lpCharLocal = &lpChar)
				{
					fixed (byte* lpKeyStateLocal = lpKeyState)
					{
						if (lpKeyState.Length < 256)							throw new ArgumentException();
						winmdroot.UI.Input.KeyboardAndMouse.HKL dwhklLocal;
						if (dwhkl is object)
						{
							dwhkl.DangerousAddRef(ref dwhklAddRef);
							dwhklLocal = (winmdroot.UI.Input.KeyboardAndMouse.HKL)dwhkl.DangerousGetHandle();
						}
						else
							dwhklLocal = (winmdroot.UI.Input.KeyboardAndMouse.HKL )new IntPtr(0L);
						int __result = PInvoke.ToAsciiEx(uVirtKey, uScanCode, lpKeyStateLocal, lpCharLocal, uFlags, dwhklLocal);
						return __result;
					}
				}
			}
			finally
			{
				if (dwhklAddRef)
					dwhkl.DangerousRelease();
			}
		}

