		/// <inheritdoc cref="ToUnicode(uint, uint, byte*, winmdroot.Foundation.PWSTR, int, uint)"/>
		[SupportedOSPlatform("windows5.0")]
		public static unsafe int ToUnicode(uint wVirtKey, uint wScanCode, [Optional] ReadOnlySpan<byte> lpKeyState, Span<char>pwszBuff, uint wFlags)
		{
			fixed (char* pwszBuffLocal = pwszBuff)
			{
				fixed (byte* lpKeyStateLocal = lpKeyState)
				{
					if (lpKeyState.Length < 256)						throw new ArgumentException();
					int __result = PInvoke.ToUnicode(wVirtKey, wScanCode, lpKeyStateLocal, pwszBuffLocal, pwszBuff.Length, wFlags);
