		public static unsafe winmdroot.Foundation.BOOL InjectSyntheticPointerInput(SafeHandle device, ReadOnlySpan<winmdroot.UI.Input.Pointer.POINTER_TYPE_INFO> pointerInfo)
		{
			bool deviceAddRef = false;
			try
			{
				fixed (winmdroot.UI.Input.Pointer.POINTER_TYPE_INFO* pointerInfoLocal = pointerInfo)
				{
					winmdroot.UI.Input.Pointer.HSYNTHETICPOINTERDEVICE deviceLocal;
					if (device is object)
					{
						device.DangerousAddRef(ref deviceAddRef);
						deviceLocal = (winmdroot.UI.Input.Pointer.HSYNTHETICPOINTERDEVICE)device.DangerousGetHandle();
