		[SupportedOSPlatform("windows5.0")]
		public static partial winmdroot.Foundation.BOOL PostMessage([Optional] winmdroot.Foundation.HWND hWnd, uint Msg, winmdroot.Foundation.WPARAM wParam, winmdroot.Foundation.LPARAM lParam);

