		/// <param name="hWnd">
		/// <para>Type: <b>HWND</b> A handle to the top-level window. The window must belong to the current process.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-setwindowdisplayaffinity#parameters">Read more on learn.microsoft.com</see>.</para>
