		/// <para><b>DrawIcon</b> places the icon's upper-left corner at the location specified by the <i>X</i> and <i>Y</i> parameters. The location is subject to the current mapping mode of the device context. <b>DrawIcon</b> draws the icon or cursor using the width and height specified by the system metric values for icons; for more information, see <a href="https://docs.microsoft.com/windows/desktop/api/winuser/nf-winuser-getsystemmetrics">GetSystemMetrics</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-drawicon#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.0")]
		public static partial winmdroot.Foundation.BOOL DrawIcon(winmdroot.Graphics.Gdi.HDC hDC, int X, int Y, winmdroot.UI.WindowsAndMessaging.HICON hIcon);

