		[SupportedOSPlatform("windows5.0")]
		[OverloadResolutionPriority(1)]
		public static unsafe Microsoft.Win32.SafeHandles.SafeFileHandle GetProp(winmdroot.Foundation.HWND hWnd, string lpString)
		{
			fixed (char* lpStringLocal = lpString)
			{
				Microsoft.Win32.SafeHandles.SafeFileHandle __resultSafeHandle = new Microsoft.Win32.SafeHandles.SafeFileHandle(default, ownsHandle: true);
				winmdroot.Foundation.HANDLE __result = PInvoke.GetProp(hWnd, lpStringLocal);
				global::System.Runtime.InteropServices.Marshal.InitHandle(__resultSafeHandle, __result);
				return __resultSafeHandle;
			}
		}

		/// <summary>Retrieves a data handle from the property list of the specified window. The character string identifies the handle to be retrieved. The string and handle must have been added to the property list by a previous call to the SetProp function. (Unicode)</summary>
		/// <param name="hWnd">
		/// <para>Type: <b>HWND</b> A handle to the window whose property list is to be searched.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-getpropw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpString">
		/// <para>Type: <b>LPCTSTR</b> An atom that identifies a string. If this parameter is an atom, it must have been created by using the <a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-globaladdatoma">GlobalAddAtom</a> function. The atom, a 16-bit value, must be placed in the low-order word of the <i>lpString</i> parameter; the high-order word must be zero.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-getpropw#parameters">Read more on learn.microsoft.com</see>.</para>
