		/// <summary>Searches through icon or cursor data for the icon or cursor that best fits the current display device. (LookupIconIdFromDirectory)</summary>
		/// <param name="presbits">
		/// <para>Type: <b>PBYTE</b> The icon or cursor directory data. Because this function does not validate the resource data, it causes a general protection (GP) fault or returns an undefined value if <i>presbits</i> is not pointing to valid resource data.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-lookupiconidfromdirectory#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
