		/// <summary>Adds or removes a message from the User Interface Privilege Isolation (UIPI) message filter.</summary>
		/// <param name="message">
		/// <para>Type: <b>UINT</b> The message to add to or remove from the filter.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-changewindowmessagefilter#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwFlag">Type: <b>DWORD</b></param>
		/// <returns>
		/// <para>Type: <b>BOOL</b> <b>TRUE</b> if successful; otherwise, <b>FALSE</b>. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// <para><div class="alert"><b>Note</b>  A message can be successfully removed from the filter, but that is not a guarantee that the message will be blocked. See the Remarks section for more details.</div> <div> </div></para>
		/// </returns>
		/// <remarks>
		/// <para>UIPI is a security feature that prevents messages from being received from a lower integrity level sender. All such messages with a value above <b>WM_USER</b> are blocked by default. The filter, somewhat contrary to intuition, is a list of messages that are allowed through. Therefore, adding a message to the filter allows that message to be received from a lower integrity sender, while removing a message blocks that message from being received. Certain messages with a value less than <b>WM_USER</b> are required to pass through the filter regardless of the filter setting. You can call this function to remove one of those messages from the filter and it will return <b>TRUE</b>. However, the message will still be received by the calling process. Processes at or below <b>SECURITY_MANDATORY_LOW_RID</b> are not allowed to change the filter. If those processes call this function, it will fail. For more information on integrity levels, see <a href="https://docs.microsoft.com/previous-versions/windows/internet-explorer/ie-developer/">Understanding and Working in Protected Mode Internet Explorer</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-changewindowmessagefilter#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows6.0.6000")]
		public static partial winmdroot.Foundation.BOOL ChangeWindowMessageFilter(uint message, winmdroot.UI.WindowsAndMessaging.CHANGE_WINDOW_MESSAGE_FILTER_FLAGS dwFlag);

		/// <inheritdoc cref="ChangeWindowMessageFilterEx(winmdroot.Foundation.HWND, uint, winmdroot.UI.WindowsAndMessaging.WINDOW_MESSAGE_FILTER_ACTION, winmdroot.UI.WindowsAndMessaging.CHANGEFILTERSTRUCT*)"/>
		[SupportedOSPlatform("windows6.1")]
		[OverloadResolutionPriority(1)]
		public static unsafe winmdroot.Foundation.BOOL ChangeWindowMessageFilterEx(winmdroot.Foundation.HWND hwnd, uint message, winmdroot.UI.WindowsAndMessaging.WINDOW_MESSAGE_FILTER_ACTION action, ref winmdroot.UI.WindowsAndMessaging.CHANGEFILTERSTRUCT pChangeFilterStruct)
		{
			fixed (winmdroot.UI.WindowsAndMessaging.CHANGEFILTERSTRUCT* pChangeFilterStructLocal = &pChangeFilterStruct)
			{
				winmdroot.Foundation.BOOL __result = PInvoke.ChangeWindowMessageFilterEx(hwnd, message, action, pChangeFilterStructLocal);
				return __result;
			}
		}

