		/// <summary>Modifies the User Interface Privilege Isolation (UIPI) message filter for a specified window.</summary>
		/// <param name="hwnd">
		/// <para>Type: <b>HWND</b> A handle to the window whose UIPI message filter is to be modified.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-changewindowmessagefilterex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="message">
		/// <para>Type: <b>UINT</b> The message that the message filter allows through or blocks.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-changewindowmessagefilterex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="action">Type: <b>DWORD</b></param>
		/// <param name="pChangeFilterStruct">
		/// <para>Type: <b>PCHANGEFILTERSTRUCT</b> Optional pointer to a <a href="https://docs.microsoft.com/windows/desktop/api/winuser/ns-winuser-changefilterstruct">CHANGEFILTERSTRUCT</a> structure.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-changewindowmessagefilterex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>Type: <b>BOOL</b> If the function succeeds, it returns <b>TRUE</b>; otherwise, it returns <b>FALSE</b>. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>UIPI is a security feature that prevents messages from being received from a lower-integrity-level sender. You can use this function to allow specific messages to be delivered to a window even if the message originates from a process at a lower integrity level. Unlike the <a href="https://docs.microsoft.com/windows/desktop/api/winuser/nf-winuser-changewindowmessagefilter">ChangeWindowMessageFilter</a> function, which controls the process message filter, the <b>ChangeWindowMessageFilterEx</b> function controls the window message filter.</para>
		/// <para>An application may use the <a href="https://docs.microsoft.com/windows/desktop/api/winuser/nf-winuser-changewindowmessagefilter">ChangeWindowMessageFilter</a> function to allow or block a message in a process-wide manner. If the message is allowed by either the process message filter or the window message filter, it will be delivered to the window.</para>
		/// <para>Note that processes at or below <b>SECURITY_MANDATORY_LOW_RID</b> are not allowed to change the message filter. If those processes call this function, it will fail and generate the extended error code, <b>ERROR_ACCESS_DENIED</b>.</para>
		/// <para>Certain messages whose value is smaller than <b>WM_USER</b> are required to be passed through the filter, regardless of the filter setting. There will be no effect when you attempt to use this function to allow or block such messages.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winuser/nf-winuser-changewindowmessagefilterex#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("USER32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows6.1")]
		public static unsafe partial winmdroot.Foundation.BOOL ChangeWindowMessageFilterEx(winmdroot.Foundation.HWND hwnd, uint message, winmdroot.UI.WindowsAndMessaging.WINDOW_MESSAGE_FILTER_ACTION action, [Optional] winmdroot.UI.WindowsAndMessaging.CHANGEFILTERSTRUCT* pChangeFilterStruct);

